import {existsSync, mkdirSync, readFileSync} from 'node:fs';
import {join} from 'node:path';
import {runVerify, type VerifyConfig} from './verify.js';
import type {ReviewProvider} from './integrator.js';
import {ledgerWrite} from './ledger-write.js';
import {selectProvider} from './github.js';
import type {IntegrationMode, ReviewProviderName} from './config.js';
import {runAsync, type RunResult} from './git.js';
import {formatProposeNextStep, shouldUseColor} from './output.js';

/**
 * `agent-runner complete [<slug>] [--skip-verify] [--type <t>] [--message <s>]
 * [--arbiter <remote>]` — the human "finish this" command that runs the same
 * back-half the autonomous runner runs: gate → mark done → commit → integrate.
 *
 * It runs on a `work/<slug>` branch (slug inferred from the branch if omitted).
 * The build agent leaves its work UNCOMMITTED (it does no git), so `complete`
 * `git add -A`s the agent's work AND the done-move into ONE atomic commit. This
 * is the same finish/integration logic `run-once`/`watch` reuse; here it is
 * human-driven and so allows a `--skip-verify` escape hatch the autonomous
 * runner never uses (ADR §8).
 *
 * The integration step is split by mode (config `integration`, ADR §6):
 *   merge   — push the rebased branch to `<arbiter>/main`, then sync the LOCAL
 *             clone to that new main (the push is authoritative; the local sync
 *             is the ergonomic finish so the user ends on an up-to-date main).
 *   propose — push the `work/<slug>` branch (the safety-bearing step) and report
 *             the next step. Full provider-driven PR/MR creation lands with the
 *             integration seam; until then `complete` pushes + tells the human.
 *
 * In BOTH modes `complete` lands the human back on local `main` by default
 * ("finish, ready for the next thing") — but the move differs because the work's
 * location differs: `merge` switches to `main` AND fast-forwards it to the just-
 * pushed `<arbiter>/main` (the work landed there); `propose` ONLY `git switch
 * main` (arbiter main has not moved, so there is nothing to ff). `--no-switch`
 * opts out in either mode (stay on `work/<slug>` to keep iterating).
 *
 * After landing on `main`, the LOCAL `work/<slug>` branch is deleted iff its work
 * is provably on the arbiter (the SAME predicate as worktree deletion, ADR §4,
 * mode-agnostic): its tip is an ancestor of `<arbiter>/main` (merged) OR
 * `<arbiter>/work/<slug>` exists with its tip == the local tip (pushed & up-to-
 * date). Otherwise the branch is KEPT (unmerged / unpushed / a diverged un-pushed
 * amend = not safe). The REMOTE branch is NEVER deleted (a propose PR is built
 * from it). `--no-switch` keeps the branch too.
 *
 * Before integrating, the work branch is rebased onto the latest `<arbiter>/main`
 * (ADR §10): a clean rebase continues; a conflicting rebase is `--abort`ed and
 * surfaced as needs-attention — `complete` NEVER auto-resolves. It NEVER
 * `--force`es to main.
 *
 * Exit codes:
 *   0  completed (done-move + commit + integrate succeeded)
 *   1  usage/environment error, or a refusal (gate failed, nothing to commit,
 *      not on a work branch, rebase conflict needs the human)
 *
 * On the two FAILURE paths the human can't paper over — a red gate (without
 * `--skip-verify`) and a rebase conflict (ADR §10) — `complete` no longer leaves
 * the item dangling. Instead it routes the item through the shared
 * `needs-attention` mechanism (ADR §12): record the reason and
 * `git mv work/in-progress|done/<slug>.md → work/needs-attention/<slug>.md`, so
 * the stuck item is surfaced by `status` and returnable to `backlog/`. The
 * success and `--skip-verify` paths are unchanged. The exit code stays 1 (the
 * work did NOT complete); the outcome still names WHY (gate-failed /
 * rebase-conflict) and `routedToNeedsAttention` records that the move happened.
 */

export type CompleteOutcome =
	| 'completed' // gated, moved, committed, integrated
	| 'gate-failed' // the acceptance gate was red (and not skipped)
	| 'rebase-conflict' // rebase onto arbiter/main conflicted (aborted; human resolves)
	| 'refused' // nothing to complete (nothing to commit, wrong folder, …)
	| 'usage-error'; // usage / environment problem

export interface CompleteOptions {
	/** The slug to complete. If omitted, inferred from a `work/<slug>` branch. */
	slug?: string;
	/** The working clone/checkout the work branch lives in. */
	cwd: string;
	/** Name of the arbiter git remote. Defaults to `origin`. */
	arbiter?: string;
	/** Integration mode: `propose` (default) or `merge`. */
	integration?: IntegrationMode;
	/**
	 * Leave the human ON the `work/<slug>` branch (and KEEP it) in either mode,
	 * instead of switching back to `main` + deleting the provably-landed branch.
	 * For "I'll keep iterating on this branch" (e.g. addressing review feedback).
	 */
	noSwitch?: boolean;
	/** The declared per-repo gate (string | list). Unset ⇒ the default command. */
	verify?: VerifyConfig;
	/** Skip the acceptance gate (human-only escape hatch; never used unattended). */
	skipVerify?: boolean;
	/** Conventional-commit type for the completion commit. Defaults to `feat`. */
	type?: string;
	/** Commit summary. Defaults to the slice `title` minus a leading `slug — `. */
	message?: string;
	/** Optional injectable PR opener (e.g. `gh pr create`); used in `propose` mode. */
	openPr?: (opts: {
		cwd: string;
		branch: string;
		env?: NodeJS.ProcessEnv;
	}) => void;
	/**
	 * The review-request provider override (config `provider`, ADR §6). Unset ⇒
	 * auto-detect from the arbiter URL (a GitHub remote ⇒ `gh pr create`, else
	 * push-only `none`); an explicit value forces a provider. Ignored when
	 * `openPr` is injected (the legacy bridge wins). `merge` mode ignores it.
	 */
	provider?: ReviewProviderName;
	/**
	 * Surface a needs-attention bounce ON THE ARBITER (the AUTONOMOUS variant of
	 * the failure path). When set, the two FAILURE routings (`gate-failed` /
	 * `rebase-conflict`) pass this arbiter remote into the ledger write seam's
	 * `applyNeedsAttentionTransition`, which (mode M) cherry-picks the move-only
	 * commit onto the arbiter's `main` — making the stuck state observable to
	 * `scan`/`status`/another machine. This is exactly what `run`'s `runOneItem`
	 * does (it passes `arbiter: job.arbiterRemote`).
	 *
	 * Unset (the default) keeps `complete`'s HUMAN behaviour: route LOCALLY only
	 * (no on-`main` surfacing) — a human is right there, so no cross-machine
	 * surfacing is needed. The unattended `do` worker (the CI command) sets this
	 * so a stuck CI run is NOT invisible.
	 */
	surfaceArbiter?: string;
	/** Environment for child git processes (identity etc.). */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
	/**
	 * Sink for a pre-formatted block printed VERBATIM (no `>> ` prefix), used for
	 * the visually-distinct propose-mode next-step block so its blank lines and
	 * heading stand out cleanly. Defaults to `note` when not supplied.
	 */
	noteBlock?: (message: string) => void;
	/**
	 * Emit ANSI color in the (cosmetic) propose-mode next-step block. Defaults
	 * to the TTY/`NO_COLOR` rule against `process.stdout`; injectable so tests
	 * can simulate a TTY (color) vs. a pipe / `NO_COLOR` (plain) without a real
	 * terminal. Color-only — it changes no gate/done-move/commit/integrate logic.
	 */
	color?: boolean;
}

export interface CompleteResult {
	exitCode: 0 | 1;
	outcome: CompleteOutcome;
	/**
	 * True iff a FAILURE outcome (gate-failed / rebase-conflict) was routed to
	 * `work/needs-attention/` via the shared mechanism (ADR §12), rather than left
	 * dangling. Undefined/false on the success, `--skip-verify`, refused, and
	 * usage-error paths (none of which move the item to needs-attention).
	 */
	routedToNeedsAttention?: boolean;
	/** The work branch that was completed, when one was resolved. */
	branch?: string;
	/** The completion commit message that was authored, on success. */
	commitMessage?: string;
	/** True when the work landed on the arbiter's `main` (merge mode). */
	mergedToMain?: boolean;
	/** The branch HEAD ended on after completing (`main`, or the work branch). */
	switchedTo?: string;
	/** True iff the local `work/<slug>` branch was deleted (provably on arbiter). */
	deletedLocalBranch?: boolean;
	/**
	 * The review-request URL (e.g. a GitHub PR) opened in `propose` mode, when a
	 * provider opened one and reported it (ADR §6). Absent in merge mode and on
	 * the push-only / degraded path.
	 */
	prUrl?: string;
	/** Human-readable summary of the terminal condition. */
	message: string;
}

const DEFAULT_ARBITER = 'origin';
const DEFAULT_TYPE = 'feat';
const DEFAULT_INTEGRATION: IntegrationMode = 'propose';

/**
 * Resolve the integration mode the human asked for ON THIS invocation from the
 * mutually-exclusive `--merge` / `--propose` flags. Returns the explicit mode,
 * or `undefined` when neither flag was given (per-repo > global > default then
 * decides). Throws when BOTH are given (they are mutually exclusive). This is
 * the TOP of the complete-time precedence chain (flag > per-repo > global >
 * default); the autonomous runner uses no flag and so resolves the same
 * underlying order.
 */
export function integrationFromFlags(flags: {
	merge?: boolean;
	propose?: boolean;
}): IntegrationMode | undefined {
	if (flags.merge && flags.propose) {
		throw new Error(
			'--merge and --propose are mutually exclusive; pass at most one.',
		);
	}
	if (flags.merge) {
		return 'merge';
	}
	if (flags.propose) {
		return 'propose';
	}
	return undefined;
}

/** Raised for usage/environment errors (exit 1, outcome 'usage-error'). */
class CompleteUsageError extends Error {}

/** Raised for a deliberate REFUSAL (exit 1, outcome 'refused'). */
class CompleteRefusal extends Error {}

/**
 * Run the complete ritual. Never throws for the expected gate-failed /
 * rebase-conflict / refused cases — those are returned with exit 1 and a
 * specific outcome. Usage/environment problems also surface as exit 1.
 */
export async function performComplete(
	options: CompleteOptions,
): Promise<CompleteResult> {
	const note = options.note ?? (() => {});
	try {
		return await runComplete(options, note);
	} catch (err) {
		if (err instanceof CompleteRefusal) {
			return {exitCode: 1, outcome: 'refused', message: err.message};
		}
		if (err instanceof CompleteUsageError) {
			return {exitCode: 1, outcome: 'usage-error', message: err.message};
		}
		const message = err instanceof Error ? err.message : String(err);
		return {exitCode: 1, outcome: 'usage-error', message};
	}
}

async function runComplete(
	options: CompleteOptions,
	note: (m: string) => void,
): Promise<CompleteResult> {
	const cwd = options.cwd;
	const env = options.env;
	const arbiter = options.arbiter ?? DEFAULT_ARBITER;
	const mode = options.integration ?? DEFAULT_INTEGRATION;

	if ((await gitSoft(['rev-parse', '--git-dir'], cwd, env)).status !== 0) {
		throw new CompleteUsageError('not inside a git repository');
	}
	if ((await gitSoft(['remote', 'get-url', arbiter], cwd, env)).status !== 0) {
		throw new CompleteUsageError(
			`no git remote named '${arbiter}' (set one, or pass --arbiter)`,
		);
	}

	// Resolve the slug: explicit wins; otherwise infer from a `work/<slug>` branch.
	const slug = options.slug || (await inferSlugFromBranch(cwd, env));
	if (!slug) {
		throw new CompleteUsageError(
			'missing <slug> and the current branch is not a work/<slug> branch. ' +
				'usage: agent-runner complete [<slug>] [--skip-verify] [--type t] ' +
				'[--message s] [--arbiter remote]',
		);
	}
	const branch = `work/${slug}`;

	// We must be ON the work branch — that is where the agent's work lives and
	// what we rebase + push. (Unlike `start`, `complete` mutates the checkout.)
	const head = await currentBranch(cwd, env);
	if (head !== branch) {
		throw new CompleteUsageError(
			`not on ${branch} (HEAD is '${head}'). ` +
				`Check out the work branch before completing '${slug}'.`,
		);
	}

	// The slice must be in-progress in the working tree (it is what we move).
	const inProgress = join(cwd, 'work', 'in-progress', `${slug}.md`);
	if (!existsSync(inProgress)) {
		throw new CompleteRefusal(
			`work/in-progress/${slug}.md not found — nothing to complete ` +
				'(already done, or wrong slug?).',
		);
	}

	// 1. Gate: bad work never proceeds to done. Default-on; --skip-verify is a
	//    human-only escape hatch (the autonomous runner never skips — ADR §8).
	if (options.skipVerify) {
		note('Skipping the acceptance gate (--skip-verify).');
	} else {
		note('Running the acceptance gate (verify)…');
		const gate = await runVerify({cwd, verify: options.verify, env});
		if (!gate.passed) {
			// Don't leave the item dangling in in-progress/: route it to
			// needs-attention/ with the reason (ADR §12) THROUGH the ledger write
			// seam's needs-attention transition. The item has NOT been committed/moved
			// yet, so the move bounces it straight from in-progress/ — recording the
			// reason + committing the move (with the agent's uncommitted work) as ONE
			// atomic transition. No partial state.
			const reason = `acceptance gate failed (exit ${gate.exitCode})`;
			const routed = ledgerWrite.applyNeedsAttentionTransition({
				cwd,
				slug,
				reason,
				// Autonomous caller (`do`) passes the arbiter so the stuck state
				// surfaces on `main` (cross-machine visible); the human `complete`
				// leaves it unset → local-only routing.
				arbiter: options.surfaceArbiter,
				env,
				note,
			});
			return {
				exitCode: 1,
				outcome: 'gate-failed',
				routedToNeedsAttention: routed.moved,
				branch,
				message: routed.moved
					? `Acceptance gate failed (exit ${gate.exitCode}); routed '${slug}' ` +
						'to work/needs-attention/ (surfaced by status; return to backlog/ ' +
						'once resolved). Fix the work, or use --skip-verify to override.'
					: `Acceptance gate failed (exit ${gate.exitCode}); not completing ` +
						`'${slug}'. Fix the work, or use --skip-verify to override.`,
			};
		}
	}

	// Read the title now, BEFORE the move, for the default commit summary (the
	// in-progress file is about to be git-mv'd away).
	const defaultMessage = defaultSummary(inProgress, slug);

	// 2. Mark done: mkdir -p work/done, then git mv in-progress → done.
	mkdirSync(join(cwd, 'work', 'done'), {recursive: true});
	await gitHard(
		['mv', `work/in-progress/${slug}.md`, `work/done/${slug}.md`],
		cwd,
		env,
	);

	// 3. Commit: git add -A (the agent's uncommitted work + the move) into ONE
	//    atomic commit. Nothing to commit is FATAL (no-op-is-fatal, like claim.sh).
	await gitHard(['add', '-A'], cwd, env);
	if (await nothingStaged(cwd, env)) {
		throw new CompleteRefusal(
			`nothing to commit for '${slug}' — no work and no move staged. ` +
				'(Did the agent produce changes? Is the slice already done?)',
		);
	}
	const summary = options.message ?? defaultMessage;
	const type = (options.type ?? DEFAULT_TYPE).trim() || DEFAULT_TYPE;
	const commitMessage = `${type}(${slug}): ${summary}; done`;
	await gitHard(['commit', '-q', '-m', commitMessage], cwd, env);
	note(`Committed: ${commitMessage}`);

	// 4. Rebase-before-integrate (ADR §10): rebase the work branch onto the
	//    latest <arbiter>/main. Clean → continue. Conflict → abort + stop.
	await gitHard(['fetch', '--quiet', arbiter], cwd, env);
	const rebase = await gitSoft(['rebase', `${arbiter}/main`], cwd, env);
	if (rebase.status !== 0) {
		// NEVER auto-resolve: abort the rebase (back to a clean work-branch tip).
		await gitSoft(['rebase', '--abort'], cwd, env);
		// Then route the item to needs-attention/ with the conflict reason (ADR
		// §12) THROUGH the ledger write seam's needs-attention transition, rather
		// than leaving it dangling in done/. The done-move was already committed
		// above, so the item sits in work/done/; the move bounces it from there and
		// commits the in-progress→needs-attention move (here done→needs-attention)
		// as ONE transition. No partial state.
		const reason = `rebase onto ${arbiter}/main conflicted (aborted, never auto-resolved)`;
		const routed = ledgerWrite.applyNeedsAttentionTransition({
			cwd,
			slug,
			reason,
			// Autonomous caller (`do`) passes the arbiter so the conflict surfaces
			// on `main` (cross-machine visible); the human `complete` leaves it
			// unset → local-only routing.
			arbiter: options.surfaceArbiter,
			env,
			note,
		});
		return {
			exitCode: 1,
			outcome: 'rebase-conflict',
			routedToNeedsAttention: routed.moved,
			branch,
			commitMessage,
			message: routed.moved
				? `Rebasing ${branch} onto ${arbiter}/main conflicted; the rebase was ` +
					`aborted (never auto-resolved) and '${slug}' was routed to ` +
					'work/needs-attention/ (surfaced by status). Resolve against the ' +
					'latest main, then return it to backlog/ and re-run.'
				: `Rebasing ${branch} onto ${arbiter}/main conflicted; the rebase was ` +
					'aborted (never auto-resolved). Resolve against the latest main, ' +
					'then re-run complete.',
		};
	}

	// 5. Integrate per mode through the ledger write seam's COMPLETE transition
	//    (ADR §6 + `docs/adr/claim-ledger-vs-protected-main.md`). The rebase above
	//    already brought the branch up to date, so the seam's sole strategy uses
	//    `integrate` (not `integrateWithRebase`) and never --forces. Provider
	//    selection: an injected `openPr` wins (legacy bridge); otherwise pick by
	//    the `provider` override LAYERED OVER auto-detection from the arbiter's
	//    remote URL (a GitHub remote ⇒ `gh pr create`, else push-only `none`). A
	//    missing/unauthenticated `gh` degrades to push-only at runtime — never a
	//    hard failure. The seam is storage-agnostic: we hand it the work branch,
	//    the integration mode, and the provider — `main` lives only in the strategy.
	const provider = options.openPr
		? bridgeProvider(options.openPr)
		: selectProvider({
				arbiterUrl: await arbiterUrl(cwd, arbiter, env),
				provider: options.provider,
			});
	const result = ledgerWrite.applyCompleteTransition({
		arbiter,
		branch,
		mode,
		provider,
		cwd,
		env,
	});

	// Land back on `main` by default in BOTH modes (the move differs per mode),
	// then delete the local work branch iff its work is provably on the arbiter.
	// `--no-switch` keeps the human on the work branch AND keeps the branch.
	let switchedTo = branch;
	let deletedLocalBranch = false;
	if (!options.noSwitch) {
		if (mode === 'merge') {
			// merge: the work landed on <arbiter>/main, so switch to main AND ff it.
			await syncLocalMain(cwd, arbiter, env);
		} else {
			// propose: the work is on a pushed branch awaiting review, NOT on main,
			// so JUST switch to main — do NOT ff (arbiter main has not moved).
			await gitHard(['switch', '--quiet', 'main'], cwd, env);
		}
		switchedTo = 'main';
		// Delete the LOCAL work branch when provably on the arbiter (same predicate
		// as worktree deletion, ADR §4, mode-agnostic). NEVER delete the remote.
		deletedLocalBranch = await deleteLocalBranchIfProvablyOnArbiter(
			cwd,
			arbiter,
			branch,
			env,
		);
	}

	if (mode === 'merge') {
		const landed = options.noSwitch
			? `merged to ${arbiter}/main; left on ${branch} (--no-switch).`
			: `merged to ${arbiter}/main; local main updated` +
				`${deletedLocalBranch ? ` and ${branch} deleted` : ''}.`;
		const message = `Completed '${slug}': ${landed}`;
		note(message);
		return {
			exitCode: 0,
			outcome: 'completed',
			branch,
			commitMessage,
			mergedToMain: result.mergedToMain,
			switchedTo,
			deletedLocalBranch,
			message,
		};
	}

	// propose: the branch is pushed; report the next step. The next step is the
	// ONE thing the human must act on, so it is emitted as a visually-distinct
	// block (blank lines + heading + TTY-aware color) ON TOP of the plain summary
	// note below — cosmetic only; the structured result is unchanged.
	const color = options.color ?? shouldUseColor(process.stdout);
	const noteBlock = options.noteBlock ?? note;
	noteBlock(
		formatProposeNextStep({
			branch,
			arbiter,
			requestOpened: result.requestOpened,
			color,
		}),
	);
	const next = result.requestOpened
		? result.url
			? `pushed ${branch} and opened a review (${result.url})`
			: `pushed ${branch} and opened a review`
		: `pushed ${branch} to ${arbiter}. ` + 'Open a PR/MR to land it on main';
	const tail = options.noSwitch
		? `; left on ${branch} (--no-switch).`
		: deletedLocalBranch
			? `; switched to main and deleted ${branch}.`
			: '; switched to main.';
	const message = `Completed '${slug}': ${next}${tail}`;
	note(message);
	return {
		exitCode: 0,
		outcome: 'completed',
		branch,
		commitMessage,
		mergedToMain: false,
		switchedTo,
		deletedLocalBranch,
		prUrl: result.url,
		message,
	};
}

/**
 * The arbiter's remote URL for `arbiter` in `cwd` (for provider auto-detection),
 * or `undefined` when it cannot be resolved. Read-only; soft (never throws).
 */
async function arbiterUrl(
	cwd: string,
	arbiter: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<string | undefined> {
	const res = await gitSoft(['remote', 'get-url', arbiter], cwd, env);
	if (res.status !== 0) {
		return undefined;
	}
	const url = res.stdout.trim();
	return url === '' ? undefined : url;
}

/** Adapt the legacy `openPr` callback into the new ReviewProvider seam. */
function bridgeProvider(
	openPr: (opts: {
		cwd: string;
		branch: string;
		env?: NodeJS.ProcessEnv;
	}) => void,
): ReviewProvider {
	return {
		name: 'none',
		openRequest(input) {
			openPr({cwd: input.cwd, branch: input.branch, env: input.env});
			return {
				opened: true,
				instruction: `Opened a review for ${input.branch}.`,
			};
		},
	};
}

/**
 * Sync the local `main` to the just-pushed `<arbiter>/main`: switch to main and
 * fast-forward it. We fetch + reset --hard to the arbiter's main (a ff in
 * practice — we just pushed our rebased work there) so the user lands on an
 * up-to-date local main without merge noise.
 */
async function syncLocalMain(
	cwd: string,
	arbiter: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<void> {
	await gitHard(['fetch', '--quiet', arbiter], cwd, env);
	await gitHard(['switch', '--quiet', 'main'], cwd, env);
	await gitHard(['merge', '--ff-only', '--quiet', `${arbiter}/main`], cwd, env);
}

/**
 * Delete the LOCAL `work/<slug>` branch iff its work is PROVABLY on the arbiter
 * — the SAME predicate as worktree deletion (ADR §4), mode-agnostic. Must be
 * called AFTER we have switched off the branch (you cannot delete the branch you
 * are on). Returns whether the local branch was deleted.
 *
 * Provably-on-arbiter ⇔ EITHER:
 *   - merged: the branch tip is an ancestor of `<arbiter>/main`, OR
 *   - pushed & up-to-date: `<arbiter>/<branch>` exists AND its tip == the local
 *     branch tip (so a later un-pushed amend is NEVER lost — we verify the
 *     remote tip equals the local tip, not merely that "a branch was pushed").
 *
 * Otherwise the branch is KEPT (unmerged / unpushed / diverged = not safe). The
 * REMOTE branch is NEVER touched (a propose PR is built from it). A `git fetch`
 * refreshes the remote-tracking refs so reachability is read against the LIVE
 * arbiter; an unreachable arbiter simply reads as not-provable → keep (safe).
 */
async function deleteLocalBranchIfProvablyOnArbiter(
	cwd: string,
	arbiter: string,
	branch: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<boolean> {
	if (!(await isLocalBranchProvablyOnArbiter(cwd, arbiter, branch, env))) {
		return false; // not provably on the arbiter → KEEP the local branch
	}
	// Provably on the arbiter → delete ONLY the local branch (force-delete: the
	// `-d` safety check uses the upstream/HEAD, which we have already proven via
	// the predicate above; `-D` avoids a false "not fully merged" in propose mode).
	await gitHard(['branch', '-D', branch], cwd, env);
	return true;
}

/**
 * The provably-safe predicate (ADR §4), mode-agnostic, applied to a LOCAL
 * `branch` in `cwd`: true iff its tip is an ancestor of `<arbiter>/main` (merged)
 * OR `<arbiter>/<branch>` exists with its tip == the local tip (pushed &
 * up-to-date). False when the local branch is absent, or its work is unmerged /
 * unpushed / a diverged un-pushed amend (remote tip != local tip). A `git fetch`
 * refreshes the remote-tracking refs; an unreachable arbiter reads as not-
 * provable → false (the safe direction). Exported for direct testing of the
 * kept-vs-deleted decision in isolation.
 */
export async function isLocalBranchProvablyOnArbiter(
	cwd: string,
	arbiter: string,
	branch: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<boolean> {
	const localTip = (
		await gitSoft(['rev-parse', '--verify', '--quiet', branch], cwd, env)
	).stdout.trim();
	if (localTip === '') {
		return false; // no such local branch
	}

	// Refresh remote-tracking refs against the live arbiter (best-effort).
	await gitSoft(['fetch', '--quiet', arbiter], cwd, env);

	// Merged: tip is an ancestor of <arbiter>/main.
	const merged =
		(
			await gitSoft(
				['merge-base', '--is-ancestor', localTip, `${arbiter}/main`],
				cwd,
				env,
			)
		).status === 0;
	if (merged) {
		return true;
	}

	// Pushed & up-to-date: <arbiter>/<branch> exists AND its tip == the local tip
	// (we verify remote-tip == local-tip so a later un-pushed amend is never lost).
	const remoteTip = (
		await gitSoft(
			['rev-parse', '--verify', '--quiet', `refs/remotes/${arbiter}/${branch}`],
			cwd,
			env,
		)
	).stdout.trim();
	return remoteTip !== '' && remoteTip === localTip;
}

/**
 * Default commit summary: the slice's `title` frontmatter with any leading
 * `slug — ` (or `slug -`) prefix stripped, so a slice titled
 * "complete — gate, mark done, …" yields "gate, mark done, …". Falls back to a
 * generic summary when the title is missing/unreadable.
 */
function defaultSummary(inProgressPath: string, slug: string): string {
	let title: string | undefined;
	try {
		title = readTitle(readFileSync(inProgressPath, 'utf8'));
	} catch {
		title = undefined;
	}
	if (!title) {
		return 'complete work slice';
	}
	// Strip a leading "slug" followed by an em-dash / en-dash / hyphen separator.
	const prefix = new RegExp(`^${escapeRegExp(slug)}\\s*[—–-]\\s*`, 'i');
	return title.replace(prefix, '').trim() || title;
}

/** Read the `title:` scalar from a slice's frontmatter block, or undefined. */
function readTitle(content: string): string | undefined {
	const normalized = content.replace(/\r\n/g, '\n').replace(/^\uFEFF/, '');
	if (!normalized.startsWith('---\n')) {
		return undefined;
	}
	const lines = normalized.split('\n');
	const closing = lines.indexOf('---', 1);
	const block = closing === -1 ? lines.slice(1) : lines.slice(1, closing);
	for (const line of block) {
		const match = /^title\s*:\s*(.*)$/.exec(line);
		if (match) {
			const value = match[1].trim();
			return value === '' ? undefined : unquote(value);
		}
	}
	return undefined;
}

function unquote(value: string): string {
	if (value.length >= 2) {
		const first = value[0];
		const last = value[value.length - 1];
		if ((first === '"' || first === "'") && last === first) {
			return value.slice(1, -1);
		}
	}
	return value;
}

function escapeRegExp(value: string): string {
	return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/** If HEAD is a `work/<slug>` branch, return `<slug>`; else ''. */
async function inferSlugFromBranch(
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<string> {
	const branch = await currentBranch(cwd, env);
	const match = /^work\/(.+)$/.exec(branch);
	return match ? match[1] : '';
}

/** The short symbolic name of HEAD, or '' for a detached HEAD. */
async function currentBranch(
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<string> {
	const sym = await gitSoft(
		['symbolic-ref', '--quiet', '--short', 'HEAD'],
		cwd,
		env,
	);
	return sym.status === 0 ? sym.stdout.trim() : '';
}

/** True when the index has no staged changes against HEAD (nothing to commit). */
async function nothingStaged(
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<boolean> {
	// `diff --cached --quiet` exits 0 when there is NOTHING staged, 1 when there is.
	const res = await gitSoft(['diff', '--cached', '--quiet'], cwd, env);
	return res.status === 0;
}

/** Run git, returning the raw result (no throw) — for soft checks. */
function gitSoft(
	args: string[],
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<RunResult> {
	return runAsync('git', args, cwd, {env});
}

/** Run git; throw on non-zero (genuinely unexpected plumbing failures). */
async function gitHard(
	args: string[],
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<RunResult> {
	const result = await runAsync('git', args, cwd, {env});
	if (result.status !== 0) {
		throw new Error(
			`git ${args.join(' ')} failed (exit ${result.status}): ${result.stderr.trim()}`,
		);
	}
	return result;
}

import {existsSync, mkdirSync, readFileSync, writeFileSync} from 'node:fs';
import {join} from 'node:path';
import {run} from './git.js';
import {ledgerRead} from './ledger-read.js';

/**
 * The folder-native **needs-attention mechanism** (ADR §12; WORK-CONTRACT
 * `needs-attention/` section). Every "couldn't finish, a human must look"
 * outcome — a failed acceptance gate (red `verify`), a rebase/merge conflict
 * (ADR §10), a slice the agent reported too ambiguous to build, a timeout, or a
 * rejected review — resolves to ONE move: the RUNNER `git mv`s the claimed item
 * from `work/in-progress/<slug>.md` to `work/needs-attention/<slug>.md`, writing
 * the reason (+ any agent-surfaced questions) into the file BODY, and commits it
 * exactly like the done-move.
 *
 * This is the conflict-safe form of "surfacing": the surface is a folder you can
 * `ls`, read by `scan`/`status` — there is **no status/label field** (honours
 * WORK-CONTRACT rule 3: status = the folder). The reason is prose in the body,
 * never a source-of-truth frontmatter field.
 *
 * Ownership: this module OWNS the mechanism (the move helper + the surface
 * reader + the return path). Consumers (`complete.ts`'s gate-failed/rebase-
 * conflict abort paths, the runner's stuck routing in `run.ts`, the human
 * `return` command) drive these through the ledger write seam's NEEDS-ATTENTION
 * transition (`ledgerWrite.applyNeedsAttentionTransition` /
 * `applyReturnToBacklogTransition` in `ledger-write.ts`), whose sole strategy
 * delegates to `routeToNeedsAttention` / `returnToBacklog` here UNCHANGED — so
 * the later cherry-pick-to-`main` surfacing is built AGAINST the seam, not
 * bolted onto this move code. The build agent NEVER does this — agents do no git
 * (ADR §12).
 */

/** Marker that opens the appended reason block in a needs-attention item body. */
const REASON_HEADING = '## Needs attention';

export interface RouteToNeedsAttentionOptions {
	/** The working clone / job worktree the `work/<slug>` branch lives in. */
	cwd: string;
	/** The slug of the in-progress item to bounce. */
	slug: string;
	/** Why the item is stuck (red gate, rebase conflict, ambiguity, timeout, …). */
	reason: string;
	/** Any questions the agent surfaced for the human, recorded under the reason. */
	questions?: string[];
	/**
	 * The arbiter remote to push the transition to (like the done-move). When
	 * omitted, the move is committed locally only (the caller pushes the branch as
	 * part of its own flow, e.g. the runner's integration step).
	 */
	arbiter?: string;
	/** Environment for child git processes (identity etc.). */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
}

export interface RouteToNeedsAttentionResult {
	/** True iff the item was moved + committed. */
	moved: boolean;
	/** When `moved`, the committed transition message (of the MOVE-ONLY commit). */
	commitMessage?: string;
	/**
	 * When `moved`, the sha of the **move-only** commit — the tip of `work/<slug>`
	 * that carries PURELY the `git mv → needs-attention/` + the reason (the wip
	 * commit holding the aborted agent work sits BELOW it). A surfacing strategy
	 * cherry-picks THIS commit to make the stuck state observable, so the wip never
	 * reaches the ledger.
	 */
	moveCommit?: string;
	/** When NOT moved, why (e.g. the slug was not in-progress). */
	reasonNotMoved?: string;
}

export interface ReturnToBacklogOptions {
	/** The working clone the `work/` tree lives in. */
	cwd: string;
	/** The slug of the needs-attention item to re-queue. */
	slug: string;
	/** The arbiter remote to push the transition to. Optional (see above). */
	arbiter?: string;
	/** Environment for child git processes. */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
}

export interface ReturnToBacklogResult {
	/** True iff the item was moved back + committed. */
	moved: boolean;
	/** When `moved`, the committed transition message. */
	commitMessage?: string;
	/** When NOT moved, why (e.g. the slug was not in needs-attention). */
	reasonNotMoved?: string;
}

export interface ResolveFromNeedsAttentionOptions {
	/** The working clone the `work/` tree lives in. */
	cwd: string;
	/** The slug of the needs-attention item to resolve back to in-progress. */
	slug: string;
	/** Environment for child git processes. */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
}

export interface ResolveFromNeedsAttentionResult {
	/** True iff the item was moved back to in-progress + committed. */
	moved: boolean;
	/** When `moved`, the committed transition message. */
	commitMessage?: string;
	/** When `moved`, the sha of the reverse move-only commit (the new tip). */
	moveCommit?: string;
	/** When NOT moved, why (e.g. the slug was not in needs-attention). */
	reasonNotMoved?: string;
}

/** The folder a pre-needs-attention item could currently live in. */
function findSourceFolder(
	cwd: string,
	slug: string,
): {rel: string; abs: string} | undefined {
	for (const folder of ['in-progress', 'done']) {
		const rel = join('work', folder, `${slug}.md`);
		const abs = join(cwd, rel);
		if (existsSync(abs)) {
			return {rel, abs};
		}
	}
	return undefined;
}

/** One needs-attention item as the surface (`status`) reads it. */
export interface NeedsAttentionItem {
	/** Filename within `work/needs-attention/` (e.g. `alpha.md`). */
	file: string;
	/** Resolved slug (frontmatter `slug:`, falling back to the filename). */
	slug: string;
	/**
	 * The recorded reason prose (the text under the `## Needs attention` heading),
	 * when present — surfaced by `status`. Empty string when no reason block was
	 * written (e.g. an item moved here by hand).
	 */
	reason: string;
}

/**
 * Route a stuck claimed item to `needs-attention/` (ADR §12). The RUNNER calls
 * this; the build agent never does. It always **saves the aborted work** and
 * produces TWO commits on `work/<slug>` (never-lose-work; PRD
 * `needs-attention-cherry-pick`):
 *
 *   1. A **wip** commit holding the aborted agent work (`git add -A` of whatever
 *      the agent left uncommitted in the tree). This is committed FIRST and
 *      stays BELOW the tip, so a surfacing strategy that publishes only the tip
 *      never leaks the half-finished work onto the ledger. When the tree is
 *      already clean (nothing uncommitted) no wip commit is made — there is no
 *      aborted work to save.
 *   2. A **move-only** commit on top (the tip): the reason appended to the file
 *      BODY (prose, NOT a frontmatter field — WORK-CONTRACT rule 3) +
 *      `git mv work/<src>/<slug>.md work/needs-attention/<slug>.md` (mkdir -p the
 *      destination first — git tracks no empty dirs). The source is whichever of
 *      `in-progress/` (the test-gate path, before the done-move) or `done/` (the
 *      rebase-conflict path, after it) the item currently sits in. This commit is
 *      PURELY the move + reason — it is the one a surfacing strategy cherry-picks.
 *
 * Optionally pushes the work branch to the arbiter (when `arbiter` given) so the
 * saved wip + the move travel cross-machine.
 *
 * NEVER throws for the expected "not in-progress/done" case — it returns
 * `{moved: false, reasonNotMoved}` so consumers can branch cleanly. Genuine git
 * plumbing failures still throw (they are unexpected).
 */
export function routeToNeedsAttention(
	options: RouteToNeedsAttentionOptions,
): RouteToNeedsAttentionResult {
	const note = options.note ?? (() => {});
	const {cwd, slug, env} = options;

	// The item could be either in-progress (test-gate path, before the done-move)
	// or already moved to done/ (rebase-conflict path, after it). Bounce from
	// whichever folder holds it.
	const source = findSourceFolder(cwd, slug);
	if (!source) {
		return {
			moved: false,
			reasonNotMoved:
				`work/in-progress/${slug}.md (nor work/done/${slug}.md) found — ` +
				'nothing to route to needs-attention (wrong slug, or not in-progress?).',
		};
	}

	// 1. WIP commit: save whatever the agent left uncommitted FIRST, so it sits
	//    BELOW the move-only tip and a tip-only surface never carries it. Skip when
	//    the tree is clean (no aborted work to save).
	gitHard(['add', '-A'], cwd, env);
	if (!nothingStaged(cwd, env)) {
		gitHard(
			['commit', '-q', '-m', `chore(${slug}): save aborted work (wip)`],
			cwd,
			env,
		);
	}

	// 2. Record the reason as PROSE in the body (never a frontmatter field), then
	//    move folders (mkdir -p first; git tracks no empty dirs — no .gitkeep), and
	//    commit the MOVE-ONLY transition (reason + the git mv, nothing else) as the
	//    tip. This is the commit a surfacing strategy cherry-picks.
	appendReasonBlock(source.abs, options.reason, options.questions);
	const destDir = join(cwd, 'work', 'needs-attention');
	mkdirSync(destDir, {recursive: true});
	const destRel = join('work', 'needs-attention', `${slug}.md`);
	gitHard(['mv', source.rel, destRel], cwd, env);
	gitHard(['add', '-A'], cwd, env);
	const commitMessage = `chore(${slug}): route to needs-attention; ${options.reason}`;
	gitHard(['commit', '-q', '-m', commitMessage], cwd, env);
	const moveCommit = revParseHead(cwd, env);
	note(`Routed '${slug}' to needs-attention: ${options.reason}`);

	// Optionally push the branch (the done-move pushes; the runner's flow may
	//    instead push as part of integration — so this is opt-in).
	if (options.arbiter) {
		const branch = `work/${slug}`;
		gitHard(['push', options.arbiter, `${branch}:${branch}`], cwd, env);
	}

	return {moved: true, commitMessage, moveCommit};
}

/**
 * The clean re-queue (ADR §12 / WORK-CONTRACT return path): once the human has
 * resolved the cause, `git mv work/needs-attention/<slug>.md
 * work/backlog/<slug>.md` and commit it so the item can be re-claimed (it must
 * not rot in needs-attention). The recorded reason block stays in the body as a
 * durable note of what happened; the resolution itself is the human's.
 *
 * Like the move, NEVER throws for the expected "not in needs-attention" case.
 */
export function returnToBacklog(
	options: ReturnToBacklogOptions,
): ReturnToBacklogResult {
	const note = options.note ?? (() => {});
	const {cwd, slug, env} = options;

	const naRel = join('work', 'needs-attention', `${slug}.md`);
	const naAbs = join(cwd, naRel);
	if (!existsSync(naAbs)) {
		return {
			moved: false,
			reasonNotMoved:
				`work/needs-attention/${slug}.md not found — nothing to return to ` +
				'backlog (wrong slug, or not in needs-attention?).',
		};
	}

	const destDir = join(cwd, 'work', 'backlog');
	mkdirSync(destDir, {recursive: true});
	const destRel = join('work', 'backlog', `${slug}.md`);
	gitHard(['mv', naRel, destRel], cwd, env);

	gitHard(['add', '-A'], cwd, env);
	const commitMessage = `chore(${slug}): return to backlog for re-claiming`;
	gitHard(['commit', '-q', '-m', commitMessage], cwd, env);
	note(`Returned '${slug}' to backlog.`);

	if (options.arbiter) {
		gitHard(['push', options.arbiter, 'HEAD'], cwd, env);
	}

	return {moved: true, commitMessage};
}

/**
 * Resolve a stuck item back to `in-progress/` (the reverse of the
 * needs-attention move) so a human can pick it up again. The clean-up half of
 * the surfacing design (PRD `needs-attention-cherry-pick`): once a human starts
 * a stuck slice, the needs-attention surface must be CLEARED and the item
 * restored to in-progress. It `git mv work/needs-attention/<slug>.md →
 * work/in-progress/<slug>.md` and commits the MOVE-ONLY transition (the recorded
 * reason stays in the body as a durable note). Returns the move commit sha so a
 * surfacing strategy can publish the reverse move to clear the ledger surface.
 *
 * Like the other moves, NEVER throws for the expected "not in needs-attention"
 * case — it returns `{moved: false, reasonNotMoved}`.
 */
export function resolveFromNeedsAttention(
	options: ResolveFromNeedsAttentionOptions,
): ResolveFromNeedsAttentionResult {
	const note = options.note ?? (() => {});
	const {cwd, slug, env} = options;

	const naRel = join('work', 'needs-attention', `${slug}.md`);
	const naAbs = join(cwd, naRel);
	if (!existsSync(naAbs)) {
		return {
			moved: false,
			reasonNotMoved:
				`work/needs-attention/${slug}.md not found — nothing to resolve back ` +
				'to in-progress (wrong slug, or not in needs-attention?).',
		};
	}

	const destDir = join(cwd, 'work', 'in-progress');
	mkdirSync(destDir, {recursive: true});
	const destRel = join('work', 'in-progress', `${slug}.md`);
	gitHard(['mv', naRel, destRel], cwd, env);

	gitHard(['add', '-A'], cwd, env);
	const commitMessage = `chore(${slug}): resolve needs-attention; return to in-progress`;
	gitHard(['commit', '-q', '-m', commitMessage], cwd, env);
	const moveCommit = revParseHead(cwd, env);
	note(`Resolved '${slug}' from needs-attention back to in-progress.`);

	return {moved: true, commitMessage, moveCommit};
}

/**
 * List the `work/needs-attention/*.md` items for a repo with their recorded
 * reason — the "look here" surface `status` renders. Read-only; returns `[]`
 * when the folder is absent (the common case). Skipped by `scan`/eligibility for
 * claiming (those read only `work/backlog/`), this is the surface companion.
 */
export function readNeedsAttentionItems(
	repoPath: string,
): NeedsAttentionItem[] {
	// Resolve the needs-attention surface THROUGH the read seam's local-tree
	// method (offline). The seam returns each item's raw `content`; we extract the
	// reason prose here, exactly as the inline read did.
	const {needsAttention} = ledgerRead.resolveLocalState({repoPath});
	return needsAttention.map((item) => ({
		file: item.file,
		slug: item.slug,
		reason: extractReason(item.content),
	}));
}

/**
 * Append the reason (and any surfaced questions) to an item file as a body
 * block. We add ONLY to the body, never the frontmatter — state stays the folder
 * (WORK-CONTRACT rule 3); the reason is durable prose. A single trailing block
 * keeps it idempotent-ish and easy to read in `ls`/`status`.
 */
function appendReasonBlock(
	path: string,
	reason: string,
	questions: string[] | undefined,
): void {
	const current = readFileSync(path, 'utf8');
	const lines: string[] = [];
	// Ensure a clear separation from whatever the body ended with.
	const base = current.replace(/\s*$/, '');
	lines.push(base);
	lines.push('');
	lines.push(REASON_HEADING);
	lines.push('');
	lines.push(reason);
	if (questions && questions.length > 0) {
		lines.push('');
		lines.push('### Surfaced questions');
		lines.push('');
		for (const q of questions) {
			lines.push(`- ${q}`);
		}
	}
	lines.push('');
	writeFileSync(path, lines.join('\n'));
}

/**
 * Extract the prose written under the `## Needs attention` heading — the reason
 * `status` surfaces. Returns the first non-empty line(s) of the block as a
 * single line (stops at the next `## ` heading); '' when no block is present.
 */
export function extractReason(content: string): string {
	const normalized = content.replace(/\r\n/g, '\n');
	const lines = normalized.split('\n');
	const start = lines.findIndex((l) => l.trim() === REASON_HEADING);
	if (start === -1) {
		return '';
	}
	const collected: string[] = [];
	for (let i = start + 1; i < lines.length; i++) {
		const line = lines[i];
		if (/^##\s/.test(line)) {
			break;
		}
		if (/^###\s/.test(line)) {
			// The questions sub-section starts here; the reason itself is above it.
			break;
		}
		if (line.trim() === '') {
			if (collected.length > 0) {
				// Stop at the first blank line AFTER we captured the reason text.
				break;
			}
			continue;
		}
		collected.push(line.trim());
	}
	return collected.join(' ').trim();
}

/** Run git; throw on non-zero (genuinely unexpected plumbing failures). */
function gitHard(
	args: string[],
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): void {
	const result = run('git', args, cwd, {env});
	if (result.status !== 0) {
		throw new Error(
			`git ${args.join(' ')} failed (exit ${result.status}): ${result.stderr.trim()}`,
		);
	}
}

/** True when the index has no staged changes against HEAD (nothing to commit). */
function nothingStaged(
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): boolean {
	// `diff --cached --quiet` exits 0 when NOTHING is staged, 1 when there is.
	return run('git', ['diff', '--cached', '--quiet'], cwd, {env}).status === 0;
}

/** The current HEAD commit sha (the just-made commit's tip). */
function revParseHead(cwd: string, env: NodeJS.ProcessEnv | undefined): string {
	const result = run('git', ['rev-parse', 'HEAD'], cwd, {env});
	if (result.status !== 0) {
		throw new Error(
			`git rev-parse HEAD failed (exit ${result.status}): ${result.stderr.trim()}`,
		);
	}
	return result.stdout.trim();
}

import {rmSync} from 'node:fs';
import {tmpdir} from 'node:os';
import {join} from 'node:path';
import {run, runAsync, type RunResult} from './git.js';
import {
	Integrator,
	type IntegrateResult,
	type ReviewProvider,
} from './integrator.js';
import type {IntegrationMode} from './config.js';
import {
	routeToNeedsAttention,
	returnToBacklog,
	resolveFromNeedsAttention,
	type RouteToNeedsAttentionOptions,
	type RouteToNeedsAttentionResult,
	type ReturnToBacklogOptions,
	type ReturnToBacklogResult,
	type ResolveFromNeedsAttentionOptions,
	type ResolveFromNeedsAttentionResult,
} from './needs-attention.js';

/**
 * The **write half** of the ledger-transition seam (ADR
 * `docs/adr/claim-ledger-vs-protected-main.md`, status: accepted — the "Write
 * seam"). ONE entry point — "apply this `work/` transition" — that every
 * transition (claim / complete / needs-attention) routes through, so a FUTURE
 * strategy could publish a transition elsewhere (e.g. a dedicated `main`-free
 * ledger ref) without the transition call sites learning a new mechanism.
 *
 * It is a PURE REFACTOR: there is exactly ONE strategy ({@link
 * currentLedgerWrite}) and it does EXACTLY what the code did before — it
 * CAS-publishes the prepared transition commit to the arbiter's `main` with
 * `--force-with-lease` and then verifies `<arbiter>/main` is now that commit. No
 * mode, no config, no `ledgerMode`, no new ref.
 *
 * The seam stays at the SEMANTIC level: the caller hands the seam a *prepared*
 * transition (a local branch carrying the commit, the base the ledger must still
 * be at for the CAS, and the commit it expects to land) plus the transition
 * KIND, and asks the seam to publish it. The public input is storage-agnostic —
 * it does NOT name `main`; that `main` is the publish/verify target is an
 * implementation detail of the sole strategy below.
 *
 * This slice routes the CLAIM transition through the seam (see `claim-cas.ts`).
 * The `complete` and `needs-attention` kinds are named here so the companion
 * slices route through the SAME entry point; they are not yet wired.
 *
 * The NEEDS-ATTENTION transition is wired here too: the abort paths in
 * `complete.ts` (red gate, rebase conflict), the runner's stuck routing in
 * `run.ts`, and the human `return` command all drive the
 * `* → needs-attention` move (and its `needs-attention → backlog` re-queue)
 * through this SAME seam rather than calling the move helpers directly. The
 * sole strategy delegates to the folder-native mechanism in
 * `needs-attention.ts` UNCHANGED (reason-in-the-body — WORK-CONTRACT rule 3,
 * bounce from in-progress OR done, ONE atomic commit, optional branch push); the
 * seam only relocates WHERE the "apply the needs-attention transition" call is
 * expressed, so the later cherry-pick-to-`main` surfacing is built AGAINST the
 * seam, not bolted onto the move code.
 */

/** The three `work/` lifecycle transitions the write seam can apply. */
export type LedgerTransitionKind = 'claim' | 'complete' | 'needs-attention';

/**
 * A *prepared* COMPLETE transition the caller asks the seam to publish: a
 * finished work branch whose code should be integrated back to the arbiter. Like
 * {@link ApplyTransitionInput} it is storage-agnostic — it names the work branch
 * + the integration MODE + the review provider, NOT *where* the integration
 * lands (the sole strategy decides that; today `merge` ff's to the arbiter's
 * `main`, `propose` pushes the branch + requests review). The caller has already
 * done the gate / done-move / commit / rebase-onto-arbiter — the seam only
 * APPLIES the integration of that prepared branch.
 */
export interface ApplyCompleteTransitionInput {
	/** Name of the arbiter git remote the integration is published to. */
	arbiter: string;
	/** The prepared (gated, committed, rebased) work branch to integrate. */
	branch: string;
	/** Integration mode: `merge` (ff to the ledger) or `propose` (push + review). */
	mode: IntegrationMode;
	/** The review-request provider (propose mode); push-only `none` otherwise. */
	provider: ReviewProvider;
	/** Working clone/worktree the integration runs in. */
	cwd: string;
	/** Environment for child git processes. */
	env?: NodeJS.ProcessEnv;
}

/**
 * The outcome of asking the seam to apply (publish) a prepared COMPLETE
 * transition. It is exactly the integration result the {@link Integrator}
 * produces — the seam adds NO interpretation, it only relocates WHERE the
 * "apply the complete transition" call is expressed.
 */
export type ApplyCompleteTransitionResult = IntegrateResult;

/**
 * A *prepared* NEEDS-ATTENTION transition the caller asks the seam to apply: a
 * stuck claimed item to bounce to `work/needs-attention/` with its reason. Like
 * the other inputs it is storage-agnostic — it names the slug, the reason prose,
 * any surfaced questions, and an OPTIONAL arbiter to also push the branch to,
 * NOT *where* the move commits/publishes (the sole strategy decides that: a
 * `git mv` from whichever of in-progress/ or done/ holds the item, the
 * reason-in-the-body, the ONE atomic commit, the optional branch push). This
 * mirrors {@link RouteToNeedsAttentionOptions} so the move mechanism is unchanged.
 */
export type ApplyNeedsAttentionTransitionInput = RouteToNeedsAttentionOptions;

/**
 * The outcome of asking the seam to apply a NEEDS-ATTENTION transition — exactly
 * the move result the folder-native mechanism produces. The seam adds NO
 * interpretation; it only relocates WHERE the call is expressed.
 */
export type ApplyNeedsAttentionTransitionResult = RouteToNeedsAttentionResult;

/**
 * A *prepared* RETURN-TO-BACKLOG transition: re-queue a resolved
 * needs-attention item so it can be re-claimed (the `needs-attention → backlog`
 * re-queue half of the needs-attention mechanism). Storage-agnostic, mirroring
 * {@link ReturnToBacklogOptions}.
 */
export type ApplyReturnToBacklogTransitionInput = ReturnToBacklogOptions;

/** The outcome of asking the seam to apply a RETURN-TO-BACKLOG transition. */
export type ApplyReturnToBacklogTransitionResult = ReturnToBacklogResult;

/**
 * A *prepared* RESOLVE-NEEDS-ATTENTION transition: a human is picking up a stuck
 * item, so the seam must **clear the stuck surface** and restore the item to
 * `in-progress`. Storage-agnostic, mirroring {@link
 * ResolveFromNeedsAttentionOptions} — it names the slug + the working clone (and
 * an OPTIONAL arbiter to clear the surface on), NOT *where* the surface lives.
 * The mode-M strategy implements "clear the surface" by reverse-moving
 * needs-attention → in-progress on the arbiter's `main`; a future strategy could
 * clear it elsewhere without `start.ts` learning a new mechanism.
 */
export type ApplyResolveNeedsAttentionTransitionInput =
	ResolveFromNeedsAttentionOptions & {
		/**
		 * The arbiter remote whose ledger surface to CLEAR (mode M: the reverse move
		 * is published to its `main`). Omitted ⇒ the local move only (no surface to
		 * clear). Storage-agnostic: it names the remote, not `main`.
		 */
		arbiter?: string;
	};

/** The outcome of asking the seam to apply a RESOLVE-NEEDS-ATTENTION transition. */
export type ApplyResolveNeedsAttentionTransitionResult =
	ResolveFromNeedsAttentionResult;

/**
 * A *prepared* transition the caller asks the seam to publish. Storage-agnostic:
 * it describes the transition semantically (a kind + a prepared local commit +
 * the CAS lease), NOT *where* it should be published. The sole strategy decides
 * that (today: the arbiter's `main`).
 */
export interface ApplyTransitionInput {
	/** Which `work/` transition this is (claim / complete / needs-attention). */
	kind: LedgerTransitionKind;
	/** Name of the arbiter git remote the transition is published to. */
	arbiter: string;
	/** Local branch carrying the prepared transition commit (its tip = {@link head}). */
	localBranch: string;
	/**
	 * The ledger commit the publish must be a fast-forward FROM — the
	 * compare-and-swap lease. If the ledger has moved past this, the publish is
	 * rejected (someone else advanced it under us).
	 */
	expectedBase: string;
	/** The commit sha the caller expects to become the ledger tip after publish. */
	head: string;
	/** Working clone/worktree the publish runs in. */
	cwd: string;
	/** Show the intended publish without mutating the arbiter (dry-run). */
	dryRun?: boolean;
	/** Environment for child git processes. */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
}

/** The outcome of asking the seam to publish a prepared transition. */
export interface ApplyTransitionResult {
	/**
	 * `published` — the transition landed (and was verified to be the ledger tip).
	 * `rejected` — the CAS lease failed (the ledger moved under us); the caller
	 * decides whether to refetch+retry or give up. The seam never throws for this
	 * expected contended case.
	 */
	kind: 'published' | 'rejected';
	/** Human-readable summary of the terminal condition. */
	message: string;
}

/**
 * The write-seam interface: ONE entry point — apply (publish) a prepared `work/`
 * transition. A future strategy implements this same interface to publish the
 * transition elsewhere — without any transition call site changing.
 */
export interface LedgerWriteStrategy {
	applyTransition(input: ApplyTransitionInput): Promise<ApplyTransitionResult>;
	/**
	 * Apply (publish) a prepared COMPLETE transition: integrate a finished work
	 * branch back to the arbiter per its mode. The sole strategy delegates to the
	 * integration mechanism unchanged; a future strategy could integrate elsewhere
	 * without `complete.ts` changing.
	 */
	applyCompleteTransition(
		input: ApplyCompleteTransitionInput,
	): ApplyCompleteTransitionResult;
	/**
	 * Apply a NEEDS-ATTENTION transition: bounce a stuck claimed item to
	 * `work/needs-attention/` with its reason recorded in the body. The sole
	 * strategy delegates to the folder-native move mechanism unchanged; a future
	 * strategy could surface the stuck item elsewhere (e.g. the cherry-pick-to-
	 * `main` follow-on) without `complete.ts`/`run.ts` changing.
	 */
	applyNeedsAttentionTransition(
		input: ApplyNeedsAttentionTransitionInput,
	): ApplyNeedsAttentionTransitionResult;
	/**
	 * Apply a RETURN-TO-BACKLOG transition: re-queue a resolved needs-attention
	 * item for re-claiming. The re-queue half of the needs-attention mechanism,
	 * routed through the SAME seam.
	 */
	applyReturnToBacklogTransition(
		input: ApplyReturnToBacklogTransitionInput,
	): ApplyReturnToBacklogTransitionResult;
	/**
	 * Apply a RESOLVE-NEEDS-ATTENTION transition: a human is picking up a stuck
	 * item, so **clear the stuck surface** and restore it to `in-progress`. The
	 * seam carries only that INTENT — "clear the surface" — NOT *how*; the sole
	 * (mode-M) strategy clears it by reverse-moving needs-attention → in-progress
	 * on the arbiter's `main`, but a future strategy could clear it differently
	 * without `start.ts` changing.
	 */
	applyResolveNeedsAttentionTransition(
		input: ApplyResolveNeedsAttentionTransitionInput,
	): ApplyResolveNeedsAttentionTransitionResult;
}

// --- The sole strategy: exactly today's behaviour -------------------------

/** Run git, returning the raw result (no throw) — for soft checks. */
function gitSoft(
	args: string[],
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<RunResult> {
	return runAsync('git', args, cwd, {env});
}

/** Run git; throw on non-zero (genuinely unexpected plumbing failures). */
async function gitHard(
	args: string[],
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<RunResult> {
	const result = await runAsync('git', args, cwd, {env});
	if (result.status !== 0) {
		throw new Error(
			`git ${args.join(' ')} failed (exit ${result.status}): ${result.stderr.trim()}`,
		);
	}
	return result;
}

/**
 * The ONLY ledger-write strategy: current behaviour. It CAS-publishes the
 * prepared transition commit to the arbiter's `main` — the `main` push and the
 * `--force-with-lease=main:<base>` lease live HERE, not in the public input — and
 * verifies the arbiter's `main` is now that commit (guarding against an
 * "Everything up-to-date" push masquerading as a successful transition). A future
 * strategy would be a different object implementing the same interface — chosen
 * NOWHERE today (no mode/config selects it).
 */
export const currentLedgerWrite: LedgerWriteStrategy = {
	async applyTransition({
		arbiter,
		localBranch,
		expectedBase,
		head,
		cwd,
		dryRun,
		env,
		note,
	}): Promise<ApplyTransitionResult> {
		const emit = note ?? (() => {});

		if (dryRun) {
			const message = `[dry-run] would: git push ${arbiter} ${localBranch}:main --force-with-lease=main:${expectedBase}`;
			emit(message);
			return {kind: 'published', message};
		}

		// The atomic compare-and-swap. --force-with-lease=main:<base> asserts the
		// arbiter's main is STILL <base> (unchanged since our fetch); the push then
		// fast-forwards main to our commit. If main moved, the lease fails → rejected.
		const push = await gitSoft(
			[
				'push',
				arbiter,
				`${localBranch}:main`,
				`--force-with-lease=main:${expectedBase}`,
			],
			cwd,
			env,
		);
		if (push.status === 0) {
			// Verify the arbiter main now points at OUR commit (not merely "up-to-date").
			await gitHard(['fetch', '--quiet', arbiter], cwd, env);
			const arbiterHead = (
				await gitHard(['rev-parse', `${arbiter}/main`], cwd, env)
			).stdout.trim();
			if (arbiterHead === head) {
				return {kind: 'published', message: 'transition published'};
			}
			emit(
				`push reported success but ${arbiter}/main is not our commit — treating as rejected.`,
			);
		}
		return {kind: 'rejected', message: 'push rejected / lease failed'};
	},

	/**
	 * The complete transition under the SAME strategy: integrate the prepared work
	 * branch back to the arbiter exactly as `complete.ts` did before — it builds
	 * the {@link Integrator} with the chosen provider and calls `integrate` (the
	 * branch was already rebased onto the latest arbiter ledger by the caller, so
	 * this is the non-rebasing `integrate`, never `--force`). `merge` ff's the
	 * branch to the arbiter's `main`; `propose` pushes the branch + asks the
	 * provider to request review. That `merge` targets `main` is an implementation
	 * detail of THIS strategy — the public input never names it.
	 */
	applyCompleteTransition({
		arbiter,
		branch,
		mode,
		provider,
		cwd,
		env,
	}): ApplyCompleteTransitionResult {
		const integrator = new Integrator({provider});
		return integrator.integrate({cwd, arbiter, branch, mode, env});
	},

	/**
	 * The needs-attention transition under the SAME strategy — satisfying the
	 * INTENT "record stuck + save work + make the stuck state OBSERVABLE." It
	 * delegates to {@link routeToNeedsAttention}, which appends the reason as body
	 * prose (never a frontmatter field — WORK-CONTRACT rule 3), saves the aborted
	 * agent work as a **wip** commit, then `git mv`s the item to
	 * `work/needs-attention/` as a **move-only** commit (the tip). Then — the
	 * surfacing this mode-M strategy adds — when an `arbiter` is given it
	 * CHERRY-PICKS the move-only commit onto the arbiter's `main`, so the stuck
	 * state is observable to `scan`/`status`/a fresh checkout/another machine (the
	 * wip never reaches `main`). That "cherry-pick to `main`" is an implementation
	 * detail of THIS strategy — the seam's contract is only the intent "make the
	 * stuck state observable," which a future mode-P strategy could satisfy by
	 * reading work-branch tips instead. The surface is published ALL-OR-NOTHING (a
	 * half-applied cherry-pick is undone), and `main` is never `--force`d.
	 *
	 * The work branch itself is NOT pushed here — the retained job worktree (with
	 * the wip + move committed on its local `work/<slug>`) IS the never-lose-work
	 * signal (ADR §4); the main surface is what travels cross-machine. The arbiter
	 * is used ONLY to publish the surface, not to push the branch.
	 */
	applyNeedsAttentionTransition(
		input: ApplyNeedsAttentionTransitionInput,
	): ApplyNeedsAttentionTransitionResult {
		// Route WITHOUT a branch push (drop `arbiter` from the move): the worktree is
		// the work-saving signal. The arbiter is reserved for surfacing on main.
		const {arbiter, ...move} = input;
		const result = routeToNeedsAttention(move);
		if (result.moved && result.moveCommit && arbiter) {
			// Make the stuck state observable on the ledger (mode M): publish ONLY the
			// move-only commit (the reason + the git mv) to the arbiter's main, so the
			// half-finished wip below it never lands there.
			publishSurfaceCommit({
				cwd: input.cwd,
				arbiter,
				slug: input.slug,
				moveCommit: result.moveCommit,
				env: input.env,
				note: input.note,
			});
		}
		return result;
	},

	/**
	 * The return-to-backlog transition under the SAME strategy: re-queue the
	 * resolved item exactly as before by delegating to {@link returnToBacklog}
	 * (`git mv work/needs-attention/<slug>.md → work/backlog/<slug>.md`, commit,
	 * optional push).
	 */
	applyReturnToBacklogTransition(
		input: ApplyReturnToBacklogTransitionInput,
	): ApplyReturnToBacklogTransitionResult {
		return returnToBacklog(input);
	},

	/**
	 * The resolve-needs-attention transition under the SAME strategy — satisfying
	 * the INTENT "clear the stuck surface + restore in-progress." It delegates to
	 * {@link resolveFromNeedsAttention} (reverse `git mv` needs-attention →
	 * in-progress, committed) and, when an `arbiter` is given, publishes that
	 * reverse move-only commit to the arbiter's `main` — CLEARING the stuck surface
	 * there (the item is back in in-progress on the ledger). Same all-or-nothing,
	 * never-`--force` publish. "Reverse-move on `main`" is a detail of THIS
	 * strategy; the seam's contract is only the intent "clear the surface."
	 */
	applyResolveNeedsAttentionTransition(
		input: ApplyResolveNeedsAttentionTransitionInput,
	): ApplyResolveNeedsAttentionTransitionResult {
		const result = resolveFromNeedsAttention(input);
		if (result.moved && result.moveCommit && input.arbiter) {
			publishSurfaceCommit({
				cwd: input.cwd,
				arbiter: input.arbiter,
				slug: input.slug,
				moveCommit: result.moveCommit,
				env: input.env,
				note: input.note,
			});
		}
		return result;
	},
};

/** The `work/` folders a slug's ledger file can live in, on `main`. */
const WORK_FOLDERS = ['backlog', 'in-progress', 'done', 'needs-attention'];

/**
 * Publish the EFFECT of a single MOVE-ONLY commit (a `work/` ledger move — a
 * route-to-needs-attention or its reverse) onto the arbiter's `main`, so the
 * stuck state is observable there (mode M). It reproduces the move-only commit's
 * placement of the slug's ledger file (which `work/<folder>/<slug>.md` it lands
 * in, with what body — including the recorded reason) ON TOP of the freshly-
 * fetched `<arbiter>/main`, and fast-forward pushes it. ONLY that one ledger file
 * is touched, so the half-finished wip / the conflicting code never reach `main`.
 *
 * It is built with plumbing on a SCRATCH INDEX (`git read-tree` + `update-index`
 * + `commit-tree`), so it NEVER touches the caller's working tree or HEAD — safe
 * to call from a job worktree mid-flight or from the human's checkout. It is
 * ALL-OR-NOTHING: it computes the full surface commit before pushing, and on any
 * failure pushes nothing (no half-surfaced state). A concurrent advance of `main`
 * is retried a few times (refetch + rebuild against the new base). The push uses
 * `--force-with-lease=main:<base>` (a true fast-forward of the fresh surface
 * commit; the lease guards the CAS) — NEVER a plain `--force` to `main`.
 *
 * Reproducing the move from `main`'s OWN state (not literally cherry-picking the
 * commit) is what makes it robust across both stuck paths: the gate-failed path's
 * commit moves `in-progress → needs-attention` while the rebase-conflict path's
 * moves `done → needs-attention`, but on `main` the item is always in
 * `in-progress/` (the done-move never reached `main`), so we always relocate from
 * wherever it actually is on `main` to the target folder the move-only commit
 * chose.
 *
 * This is the mode-M MECHANISM, deliberately living inside the strategy — NOT in
 * the seam's public contract: a future mode-P strategy would make the same stuck
 * state observable WITHOUT writing `main` (e.g. reading work-branch tips).
 */
function publishSurfaceCommit(params: {
	cwd: string;
	arbiter: string;
	slug: string;
	moveCommit: string;
	env?: NodeJS.ProcessEnv;
	note?: (message: string) => void;
}): void {
	const {cwd, arbiter, slug, moveCommit, env} = params;
	const emit = params.note ?? (() => {});
	const gx = (args: string[], input?: string): RunResult =>
		run('git', args, cwd, {env, input});
	const gxHard = (args: string[], input?: string): RunResult => {
		const r = gx(args, input);
		if (r.status !== 0) {
			throw new Error(
				`git ${args.join(' ')} failed (exit ${r.status}): ${r.stderr.trim()}`,
			);
		}
		return r;
	};

	// Where the slug's ledger file lands AFTER the move (per the move-only commit's
	// tree) — the placement we mirror onto main. Exactly one of WORK_FOLDERS holds
	// it; we read its path + content from the commit's tree (plumbing, no checkout).
	const target = readLedgerPlacement(gx, moveCommit, slug);
	if (!target) {
		emit('could not resolve the surfaced ledger file from the move commit.');
		return;
	}

	// A scratch index so update-index/write-tree never disturb the caller's index.
	const scratchIndex = join(
		tmpdir(),
		`agent-runner-surface-${process.pid}-${Date.now()}.index`,
	);
	const withIndex: NodeJS.ProcessEnv = {
		...(env ?? process.env),
		GIT_INDEX_FILE: scratchIndex,
	};
	const sx = (args: string[], input?: string): RunResult =>
		run('git', args, cwd, {env: withIndex, input});
	const sxHard = (args: string[], input?: string): RunResult => {
		const r = sx(args, input);
		if (r.status !== 0) {
			throw new Error(
				`git ${args.join(' ')} failed (exit ${r.status}): ${r.stderr.trim()}`,
			);
		}
		return r;
	};

	const attempts = 5;
	try {
		for (let i = 0; i < attempts; i++) {
			gxHard([
				'fetch',
				'--quiet',
				arbiter,
				`+refs/heads/main:refs/remotes/${arbiter}/main`,
			]);
			const base = gxHard(['rev-parse', `${arbiter}/main`]).stdout.trim();

			// Load main's tree into the scratch index, then relocate ONLY this slug's
			// ledger file to the target folder (remove it from every other work folder,
			// write the move commit's blob at the target path). One file changes.
			rmSync(scratchIndex, {force: true});
			sxHard(['read-tree', base]);
			for (const folder of WORK_FOLDERS) {
				const path = `work/${folder}/${slug}.md`;
				if (path !== target.path) {
					// Remove if present (force-remove tolerates an absent path).
					sx(['update-index', '--force-remove', path]);
				}
			}
			sxHard([
				'update-index',
				'--add',
				'--cacheinfo',
				`100644,${target.blob},${target.path}`,
			]);
			const tree = sxHard(['write-tree']).stdout.trim();
			const commit = gxHard([
				'commit-tree',
				tree,
				'-p',
				base,
				'-m',
				target.message,
			]).stdout.trim();

			// Fast-forward push the surface commit to main (the lease guards the CAS).
			// NEVER a plain --force.
			const push = gx([
				'push',
				arbiter,
				`${commit}:main`,
				`--force-with-lease=main:${base}`,
			]);
			if (push.status === 0) {
				emit(`Surfaced the stuck state on ${arbiter}/main.`);
				return;
			}
			// Contended: someone advanced main. Loop to refetch + rebuild against it.
		}
		emit(
			`could not surface the stuck state on ${arbiter}/main after ${attempts} ` +
				'attempts (main kept moving) — left unsurfaced.',
		);
	} finally {
		rmSync(scratchIndex, {force: true});
	}
}

/**
 * Read, from a move-only commit's tree, WHICH `work/<folder>/<slug>.md` the slug
 * lands in, plus that file's blob sha + a surface commit message. Returns
 * `undefined` if the slug's ledger file is not found (nothing to surface). The
 * move commit's tree has exactly one such file for the slug.
 */
function readLedgerPlacement(
	gx: (args: string[]) => RunResult,
	moveCommit: string,
	slug: string,
): {path: string; blob: string; message: string} | undefined {
	// Find THIS slug's ledger file in the move commit's tree (the post-move
	// placement). Probe each work folder for `work/<folder>/<slug>.md` and read its
	// blob sha; exactly one holds it after the move.
	for (const folder of WORK_FOLDERS) {
		const path = `work/${folder}/${slug}.md`;
		const ls = gx(['ls-tree', moveCommit, path]);
		if (ls.status !== 0 || ls.stdout.trim() === '') {
			continue;
		}
		// `<mode> blob <sha>\t<path>`
		const match = /^\d+ blob ([0-9a-f]+)\t/.exec(ls.stdout.trim());
		if (!match) {
			continue;
		}
		const blob = match[1];
		const message =
			folder === 'needs-attention'
				? `chore(${slug}): surface needs-attention on main`
				: `chore(${slug}): clear needs-attention surface on main (${folder})`;
		return {path, blob, message};
	}
	return undefined;
}

/**
 * The active ledger-write strategy. There is exactly one (current behaviour);
 * this indirection is the seam's single insertion point — NOT a selectable mode.
 */
export const ledgerWrite: LedgerWriteStrategy = currentLedgerWrite;

import {describe, it, expect, beforeEach, afterEach} from 'vitest';
import {writeFileSync, readFileSync, existsSync} from 'node:fs';
import {join} from 'node:path';
import {performComplete} from '../src/complete.js';
import {readNeedsAttentionItems} from '../src/needs-attention.js';
import {performClaim} from '../src/claim-cas.js';
import {
	makeScratch,
	seedRepoWithArbiter,
	existsOnArbiterMain,
	gitEnv,
	gitIn,
	type Scratch,
} from './helpers/gitRepo.js';

let scratch: Scratch;

beforeEach(() => {
	scratch = makeScratch('agent-runner-complete-na-');
});
afterEach(() => {
	scratch.cleanup();
});

const ARBITER = 'arbiter';

function currentBranch(repo: string): string {
	return gitIn(['rev-parse', '--abbrev-ref', 'HEAD'], repo).trim();
}

/**
 * Stand a repo up exactly as the human loop leaves it just before `complete`:
 * a slice claimed (in-progress on the arbiter) and the human onboarded onto
 * `work/<slug>` off the freshly-pushed main.
 */
async function claimAndBranch(
	slug: string,
	opts: {extraSlugs?: string[]} = {},
): Promise<{repo: string; seeded: ReturnType<typeof seedRepoWithArbiter>}> {
	const seeded = seedRepoWithArbiter(scratch.root, [
		slug,
		...(opts.extraSlugs ?? []),
	]);
	const repo = seeded.repo;
	const claim = await performClaim({
		slug,
		cwd: repo,
		arbiter: ARBITER,
		env: gitEnv(),
	});
	expect(claim.exitCode).toBe(0);
	gitIn(['fetch', '-q', ARBITER], repo);
	gitIn(['switch', '-q', '-c', `work/${slug}`, `${ARBITER}/main`], repo);
	return {repo, seeded};
}

/** Simulate the build agent: leave UNCOMMITTED work in the tree (no git). */
function agentEdits(repo: string, file = 'feature.txt', body = 'the work\n') {
	writeFileSync(join(repo, file), body);
}

const PASS = 'exit 0';
const FAIL = 'exit 1';

describe('complete — failed gate routes to needs-attention', () => {
	it('moves the item in-progress → needs-attention with the reason recorded', async () => {
		const {repo} = await claimAndBranch('alpha');
		agentEdits(repo);

		const result = await performComplete({
			slug: 'alpha',
			cwd: repo,
			arbiter: ARBITER,
			verify: FAIL,
			env: gitEnv(),
		});

		// Exit 1 (the work did not complete) and the gate-failed outcome stands.
		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('gate-failed');
		expect(result.routedToNeedsAttention).toBe(true);

		// The item is no longer dangling in in-progress/ — it moved to
		// needs-attention/ (not done/).
		expect(existsSync(join(repo, 'work', 'in-progress', 'alpha.md'))).toBe(
			false,
		);
		expect(existsSync(join(repo, 'work', 'done', 'alpha.md'))).toBe(false);
		const dest = join(repo, 'work', 'needs-attention', 'alpha.md');
		expect(existsSync(dest)).toBe(true);

		// The reason is recorded as prose in the body (no status/label field).
		const body = readFileSync(dest, 'utf8');
		expect(body).toMatch(/Needs attention/i);
		expect(body).toMatch(/gate failed/i);

		// Surfaced by readNeedsAttentionItems with that reason.
		const items = readNeedsAttentionItems(repo);
		expect(items.find((i) => i.slug === 'alpha')?.reason).toMatch(
			/gate failed/i,
		);
	});

	it('no partial state: aborted work saved (wip) + move-only tip, clean tree', async () => {
		const {repo} = await claimAndBranch('beta');
		agentEdits(repo);

		const result = await performComplete({
			slug: 'beta',
			cwd: repo,
			arbiter: ARBITER,
			verify: FAIL,
			env: gitEnv(),
		});
		expect(result.routedToNeedsAttention).toBe(true);

		// Working tree is clean (everything was staged + committed). No partial state.
		expect(gitIn(['status', '--porcelain'], repo).trim()).toBe('');
		// TWO commits (needs-attention-surface-on-main): the MOVE-ONLY tip is purely
		// the git mv (no agent file), and the wip commit below it saves the aborted
		// work — so a surfacing strategy can publish the tip without leaking the wip.
		const tip = gitIn(['show', '--name-status', '--format=', 'HEAD'], repo);
		expect(tip).toMatch(/work\/needs-attention\/beta\.md/);
		expect(tip).toMatch(/work\/in-progress\/beta\.md/);
		expect(tip).not.toMatch(/feature\.txt/);
		const wip = gitIn(['show', '--name-status', '--format=', 'HEAD~1'], repo);
		expect(wip).toMatch(/feature\.txt/);
		// Not mid-rebase, not detached.
		expect(currentBranch(repo)).toBe('work/beta');
	});

	it('--skip-verify is unchanged: completes, no needs-attention move', async () => {
		const {repo} = await claimAndBranch('gamma');
		agentEdits(repo);

		const result = await performComplete({
			slug: 'gamma',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'propose',
			skipVerify: true,
			verify: FAIL, // would fail if run — proving it is skipped
			noSwitch: true,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(0);
		expect(result.outcome).toBe('completed');
		expect(result.routedToNeedsAttention).toBeFalsy();
		expect(existsSync(join(repo, 'work', 'done', 'gamma.md'))).toBe(true);
		expect(existsSync(join(repo, 'work', 'needs-attention', 'gamma.md'))).toBe(
			false,
		);
	});
});

describe('complete — rebase conflict routes to needs-attention', () => {
	it('aborts the rebase, then moves the item to needs-attention with the conflict reason', async () => {
		const {seeded, repo} = await claimAndBranch('theta');
		// Our work edits README.md.
		writeFileSync(join(repo, 'README.md'), '# project\nour change\n');

		// Concurrently, another clone advances arbiter/main with a CONFLICTING edit.
		const other = seeded.clone('conflict');
		writeFileSync(join(other, 'README.md'), '# project\ntheir change\n');
		gitIn(['add', '-A'], other);
		gitIn(['commit', '-q', '-m', 'conflicting advance'], other);
		gitIn(['push', '-q', ARBITER, 'main:main'], other);

		const result = await performComplete({
			slug: 'theta',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			env: gitEnv(),
		});

		expect(result.exitCode).toBe(1);
		expect(result.outcome).toBe('rebase-conflict');
		expect(result.routedToNeedsAttention).toBe(true);

		// The rebase was aborted (not mid-rebase).
		expect(existsSync(join(repo, '.git', 'rebase-merge'))).toBe(false);
		expect(existsSync(join(repo, '.git', 'rebase-apply'))).toBe(false);

		// Item moved to needs-attention/ (it was in done/ after the done-move).
		expect(existsSync(join(repo, 'work', 'done', 'theta.md'))).toBe(false);
		expect(existsSync(join(repo, 'work', 'in-progress', 'theta.md'))).toBe(
			false,
		);
		const dest = join(repo, 'work', 'needs-attention', 'theta.md');
		expect(existsSync(dest)).toBe(true);
		expect(readFileSync(dest, 'utf8')).toMatch(/conflict/i);

		// Nothing landed on arbiter main.
		expect(existsOnArbiterMain(repo, 'done', 'theta')).toBe(false);

		// Surfaced with the conflict reason.
		const items = readNeedsAttentionItems(repo);
		expect(items.find((i) => i.slug === 'theta')?.reason).toMatch(/conflict/i);
	});

	it('no partial state on conflict: clean tree, still on the work branch', async () => {
		const {seeded, repo} = await claimAndBranch('kappa');
		writeFileSync(join(repo, 'README.md'), '# project\nour change\n');
		const other = seeded.clone('conflict2');
		writeFileSync(join(other, 'README.md'), '# project\ntheir change\n');
		gitIn(['add', '-A'], other);
		gitIn(['commit', '-q', '-m', 'conflicting advance'], other);
		gitIn(['push', '-q', ARBITER, 'main:main'], other);

		const result = await performComplete({
			slug: 'kappa',
			cwd: repo,
			arbiter: ARBITER,
			integration: 'merge',
			verify: PASS,
			env: gitEnv(),
		});
		expect(result.routedToNeedsAttention).toBe(true);
		expect(gitIn(['status', '--porcelain'], repo).trim()).toBe('');
		expect(currentBranch(repo)).toBe('work/kappa');
	});
});

import {mkdtempSync, mkdirSync, writeFileSync, rmSync} from 'node:fs';
import {tmpdir} from 'node:os';
import {dirname, join} from 'node:path';
import {run, git} from '../../src/git.js';
import {mirrorPath} from '../../src/repo-mirror.js';

/**
 * Deterministic git identity + non-interactive env for throwaway test repos.
 *
 * Crucially, it ISOLATES git from the developer's / CI's real global + system
 * config: `GIT_CONFIG_GLOBAL=/dev/null`, `GIT_CONFIG_SYSTEM=/dev/null` and
 * `GIT_CONFIG_NOSYSTEM=1` mean every test git invocation sees ONLY the repo-local
 * config it sets up. Without this, all tests share the real `~/.gitconfig`
 * (identity, `includeIf`, hooks, `core.*`), which both pollutes results and is a
 * contention/interference point when many test files run git concurrently.
 */
export function gitEnv(): NodeJS.ProcessEnv {
	return {
		...process.env,
		GIT_AUTHOR_NAME: 'Test Runner',
		GIT_AUTHOR_EMAIL: 'test@example.com',
		GIT_COMMITTER_NAME: 'Test Runner',
		GIT_COMMITTER_EMAIL: 'test@example.com',
		GIT_TERMINAL_PROMPT: '0',
		GIT_CONFIG_GLOBAL: '/dev/null',
		GIT_CONFIG_SYSTEM: '/dev/null',
		GIT_CONFIG_NOSYSTEM: '1',
	};
}

/** A scratch workspace that cleans itself up. */
export interface Scratch {
	root: string;
	cleanup(): void;
}

export function makeScratch(prefix = 'agent-runner-git-'): Scratch {
	const root = mkdtempSync(join(tmpdir(), prefix));
	return {
		root,
		cleanup() {
			rmSync(root, {recursive: true, force: true});
		},
	};
}

function gx(args: string[], cwd: string): string {
	return git(args, cwd, {env: gitEnv()});
}

/**
 * Build a throwaway project repo with a `work/backlog/<slug>.md` for each given
 * slug, plus a sibling local `--bare` arbiter the project pushes its `main` to.
 * Returns the working-clone path, the arbiter path, and a `clone()` that makes
 * an additional independent clone of the arbiter (for parallel isolation tests).
 */
export interface SeededRepo {
	repo: string;
	arbiter: string;
	clone(label: string): string;
}

export function seedRepoWithArbiter(
	root: string,
	slugs: string[],
	opts: {
		humanOnly?: boolean;
		needsAnswers?: boolean;
		blockedBy?: string[];
		promptBody?: string;
	} = {},
): SeededRepo {
	const repo = join(root, 'project');
	mkdirSync(repo, {recursive: true});
	gx(['init', '-q', '-b', 'main'], repo);

	const backlog = join(repo, 'work', 'backlog');
	mkdirSync(backlog, {recursive: true});
	for (const slug of slugs) {
		writeFileSync(join(backlog, `${slug}.md`), sliceFile(slug, opts));
	}
	writeFileSync(join(repo, 'README.md'), '# project\n');
	gx(['add', '-A'], repo);
	gx(['commit', '-q', '-m', 'seed'], repo);

	// Bare arbiter next to (not inside) the working clone.
	const arbiter = join(root, 'project-work.git');
	gx(['clone', '-q', '--bare', repo, arbiter], root);
	gx(['remote', 'add', 'arbiter', `file://${arbiter}`], repo);
	gx(['fetch', '-q', 'arbiter'], repo);

	let n = 0;
	return {
		repo,
		arbiter,
		clone(label: string): string {
			const dest = join(root, `clone-${label}-${n++}`);
			gx(['clone', '-q', `file://${arbiter}`, dest], root);
			gx(['remote', 'add', 'arbiter', `file://${arbiter}`], dest);
			gx(['fetch', '-q', 'arbiter'], dest);
			return dest;
		},
	};
}

function sliceFile(
	slug: string,
	opts: {
		humanOnly?: boolean;
		needsAnswers?: boolean;
		blockedBy?: string[];
		promptBody?: string;
	},
): string {
	const body = opts.promptBody ?? `> Implement ${slug}.`;
	const gateLines = [
		...(opts.humanOnly === true ? ['humanOnly: true'] : []),
		...(opts.needsAnswers === true ? ['needsAnswers: true'] : []),
	];
	const blockedBy =
		opts.blockedBy && opts.blockedBy.length > 0
			? `blockedBy: [${opts.blockedBy.join(', ')}]`
			: 'blockedBy: []';
	return [
		'---',
		`title: ${slug}`,
		`slug: ${slug}`,
		...gateLines,
		blockedBy,
		'---',
		'',
		'## What to build',
		'',
		'thing',
		'',
		'## Acceptance criteria',
		'',
		'- [ ] works',
		'',
		'## Prompt',
		'',
		body,
		'',
	].join('\n');
}

/**
 * Seed a `work/done/<slug>.md` directly onto `<arbiter>/main` (simulating a
 * completed dependency), via a throwaway clone so the checkout under test is
 * left untouched. Used to satisfy a slice's `blockedBy` for readiness tests.
 */
export function seedDoneOnArbiter(seeded: SeededRepo, slug: string): void {
	const dest = join(seeded.repo, '..', `seed-done-${slug}`);
	gx(['clone', '-q', `file://${seeded.arbiter}`, dest], seeded.repo);
	gx(['remote', 'add', 'arbiter', `file://${seeded.arbiter}`], dest);
	gx(['fetch', '-q', 'arbiter'], dest);
	gx(['checkout', '-q', '-B', `seed-done/${slug}`, 'arbiter/main'], dest);
	const doneDir = join(dest, 'work', 'done');
	mkdirSync(doneDir, {recursive: true});
	writeFileSync(join(doneDir, `${slug}.md`), sliceFile(slug, {}));
	gx(['add', '-A'], dest);
	gx(['commit', '-q', '-m', `done: ${slug}`], dest);
	gx(['push', '-q', 'arbiter', `seed-done/${slug}:main`], dest);
	rmSync(dest, {recursive: true, force: true});
}

/** Does `<arbiter>/main` currently track `work/<status>/<slug>.md`? */
export function existsOnArbiterMain(
	cwd: string,
	status: 'backlog' | 'in-progress' | 'needs-attention' | 'done',
	slug: string,
): boolean {
	run('git', ['fetch', '-q', 'arbiter'], cwd, {env: gitEnv()});
	const res = run(
		'git',
		['cat-file', '-e', `arbiter/main:work/${status}/${slug}.md`],
		cwd,
		{env: gitEnv()},
	);
	return res.status === 0;
}

/**
 * Register a BARE hub mirror under `<workspacesDir>/repos/<key>.git` whose
 * `main` ref carries the given `work/` content — the registry-model fixture for
 * `scan`/`status` (which read each mirror's bare `main` ref, NOT a working tree).
 *
 * It builds a throwaway WORKING repo with the `work/` files committed on `main`,
 * then `git clone --bare`s it into the mirror location (so `origin` points at
 * the source repo — a `file://` URL, transport `local-bare`). The mirror is keyed
 * off that origin URL via `mirrorPath`, exactly as `remote add`/`ensureMirror`
 * key it. Returns the mirror path + its origin URL.
 */
export interface RegisteredMirrorFixture {
	mirrorPath: string;
	originUrl: string;
}

export function registerMirrorWithWork(
	workspacesDir: string,
	name: string,
	work: {
		backlog?: Record<string, string>;
		done?: Record<string, string>;
		needsAttention?: Record<string, string>;
	},
): RegisteredMirrorFixture {
	// 1. A throwaway working repo (the would-be arbiter source) with the work/ tree.
	const src = join(workspacesDir, '..', `mirror-src-${name}`);
	mkdirSync(src, {recursive: true});
	gx(['init', '-q', '-b', 'main'], src);
	const writeAll = (
		folder: string,
		files: Record<string, string> | undefined,
	) => {
		if (!files) {
			return;
		}
		const dir = join(src, 'work', folder);
		mkdirSync(dir, {recursive: true});
		for (const [file, content] of Object.entries(files)) {
			writeFileSync(join(dir, file), content);
		}
	};
	writeAll('backlog', work.backlog);
	writeAll('done', work.done);
	writeAll('needs-attention', work.needsAttention);
	writeFileSync(join(src, 'README.md'), `# ${name}\n`);
	gx(['add', '-A'], src);
	gx(['commit', '-q', '-m', 'seed work tree'], src);

	// 2. The bare hub mirror, keyed off the source's file:// URL (as ensureMirror).
	const originUrl = `file://${src}`;
	const dest = mirrorPath(workspacesDir, originUrl);
	mkdirSync(dirname(dest), {recursive: true});
	gx(['clone', '--quiet', '--bare', originUrl, dest], dirname(dest));
	return {mirrorPath: dest, originUrl};
}

