import {it, expect, beforeEach, afterEach} from 'vitest';
import {writeFileSync} from 'node:fs';
import {join} from 'node:path';
import {performComplete} from '../src/complete.js';
import {ledgerWrite} from '../src/ledger-write.js';
import {performClaim} from '../src/claim-cas.js';
import {
	makeScratch,
	seedRepoWithArbiter,
	gitEnv,
	gitIn,
	type Scratch,
} from './helpers/gitRepo.js';

let scratch: Scratch;
beforeEach(() => {
	scratch = makeScratch('dbg-');
});
afterEach(() => {
	scratch.cleanup();
});

it('dbg', async () => {
	const seeded = seedRepoWithArbiter(scratch.root, ['alpha']);
	const repo = seeded.repo;
	await performClaim({slug: 'alpha', cwd: repo, arbiter: 'arbiter', env: gitEnv()});
	gitIn(['fetch', '-q', 'arbiter'], repo);
	gitIn(['switch', '-q', '-c', 'work/alpha', 'arbiter/main'], repo);
	writeFileSync(join(repo, 'feature.txt'), 'the work\n');
	ledgerWrite.applyNeedsAttentionTransition({
		cwd: repo,
		slug: 'alpha',
		reason: 'gate failed',
		arbiter: 'arbiter',
		env: gitEnv(),
	});
	process.stderr.write('DBG LOG:\n' + gitIn(['log', '--oneline', '--all'], repo) + '\n');
	const r = await performComplete({
		slug: 'alpha',
		cwd: repo,
		arbiter: 'arbiter',
		integration: 'merge',
		verify: 'exit 0',
		surfaceArbiter: 'arbiter',
		env: gitEnv(),
		note: (m) => process.stderr.write('DBG NOTE: ' + m + '\n'),
	});
	process.stderr.write('DBG RESULT: ' + JSON.stringify(r) + '\n');
	expect(r.outcome).toBe('completed');
});

